CREATE VIEW `ads_advertisement_admob_income_view` (`dt` COMMENT "日期，来自DATE字段", `id` COMMENT "自增id", `time_types` COMMENT "时区类型 1北京 2洛杉矶", `ad_unit` COMMENT "广告单元id", `plat_form` COMMENT "系统", `ad_source` COMMENT "广告来源", `name` COMMENT "广告来源名字", `app` COMMENT "appid", `ad_requests` COMMENT "请求的数量。该值是一个整数。", `clicks` COMMENT "用户点击广告的次数。该值是一个整数。", `ad_amount` COMMENT "AdMob 发布商的估算收入 ESTIMATED_EARNINGS/1000000,单位，美元", `impressions` COMMENT "向用户展示的广告总数。该值是一个整数。", `matched_requests` COMMENT "响应请求而返回广告的次数。该值是一个整数。", `match_rate` COMMENT "匹配的广告请求与总广告请求的比率。该值是双精度（近似）十进制值。", `observed_ecpm` COMMENT "第三方广告网络的估计平均 eCPM 例如，$2.30 将表示为 2300000", `account` COMMENT "广告账户", `create_time` COMMENT "创建时间", `Update_Time` COMMENT "更新时间", `etl_time` COMMENT "数据清洗时间", `appver`)
COMMENT "广告语admob广告收入事实表" AS SELECT `dwd`.`dwd_advertisement_admob_income`.`dt`, `dwd`.`dwd_advertisement_admob_income`.`id`, `dwd`.`dwd_advertisement_admob_income`.`time_types`, `dwd`.`dwd_advertisement_admob_income`.`ad_unit`, `dwd`.`dwd_advertisement_admob_income`.`plat_form`, `dwd`.`dwd_advertisement_admob_income`.`ad_source`, `dwd`.`dwd_advertisement_admob_income`.`name`, `dwd`.`dwd_advertisement_admob_income`.`app`, `dwd`.`dwd_advertisement_admob_income`.`ad_requests`, `dwd`.`dwd_advertisement_admob_income`.`clicks`, `dwd`.`dwd_advertisement_admob_income`.`ad_amount`, `dwd`.`dwd_advertisement_admob_income`.`impressions`, `dwd`.`dwd_advertisement_admob_income`.`matched_requests`, `dwd`.`dwd_advertisement_admob_income`.`match_rate`, `dwd`.`dwd_advertisement_admob_income`.`observed_ecpm`, `dwd`.`dwd_advertisement_admob_income`.`account`, `dwd`.`dwd_advertisement_admob_income`.`create_time`, `dwd`.`dwd_advertisement_admob_income`.`Update_Time`, `dwd`.`dwd_advertisement_admob_income`.`etl_time`, `dwd`.`dwd_advertisement_admob_income`.`appver`
FROM `dwd`.`dwd_advertisement_admob_income`;